def load_state() -> dict[str, Any]:
    if not STATE_PATH.exists():
        return controller_defaults()
    return json.loads(STATE_PATH.read_text(encoding="utf-8"))


def save_state(state: dict[str, Any]) -> None:
    state["updated_at"] = now_iso()
    atomic_write_json(STATE_PATH, state)


def job_path(job_id: str) -> Path:
    return JOBS_ROOT / job_id / "status.json"


def load_job(job_id: str) -> dict[str, Any]:
    path = job_path(job_id)
    if not path.exists():
        raise FileNotFoundError(f"Job not found: {job_id}")
    return json.loads(path.read_text(encoding="utf-8"))


def save_job(job: dict[str, Any]) -> None:
    job["updated_at"] = now_iso()
    atomic_write_json(job_path(job["job_id"]), job)


def heartbeat(job: dict[str, Any], step: str, completed_step: str | None = None) -> None:
    job["current_step"] = step
    job["last_heartbeat"] = now_iso()
    if completed_step and completed_step not in job["completed_steps"]:
        job["completed_steps"].append(completed_step)
    save_job(job)


def output(payload: dict[str, Any]) -> None:
    print(json.dumps(payload, indent=2, sort_keys=True))


def verify_checkpoint() -> dict[str, Any]:
    branch = git_output(["branch", "--show-current"])
    head = git_output(["rev-parse", "HEAD"])
    tag_commit = git_output(["rev-list", "-n", "1", EXPECTED_PREVIOUS_TAG])
    if branch != EXPECTED_BRANCH:
        raise RuntimeError(f"Expected branch {EXPECTED_BRANCH}, found {branch}")
    if tag_commit != head:
        raise RuntimeError(
            f"{EXPECTED_PREVIOUS_TAG} points to {tag_commit}, but HEAD is {head}"
        )
    return {"branch": branch, "head": head, "tag": EXPECTED_PREVIOUS_TAG}


def source_manifest() -> list[dict[str, Any]]:
    exact = [
        "docs/phase-9e-extended-roadmap.md",
        "docs/council-runtime-architecture.md",
        "docs/conversation-runtime-architecture.md",
        "docs/event-sourcing-schema.md",
        "runtime/council_runtime.py",
        "runtime/conversation_runtime.py",
        "runtime/shared_event_runtime.py",
        "runtime/operator_runtime.py",
        "runtime_registry.yaml",
    ]
    patterns = [
        "docs/*govern*.md",
        "docs/*autonomy*.md",
        "docs/*sentinel*.md",
        "docs/*constitution*.md",
        "docs/*approval*.md",
        "docs/*agent*.md",
        "docs/*memory*.md",
        "docs/*journal*.md",
        "docs/*relationship*.md",
    ]
    paths: dict[str, Path] = {}
    for rel in exact:
        path = REPO / rel
        if path.is_file():
            paths[rel] = path
    for pattern in patterns:
        for path in REPO.glob(pattern):
            if path.is_file():
                paths[path.relative_to(REPO).as_posix()] = path
    result = []
    for rel, path in sorted(paths.items()):
        result.append(
            {
                "path": rel,
                "sha256": sha256_file(path),
                "size_bytes": path.stat().st_size,
            }
        )
    return result


def validate_markdown(path: Path, required_headings: list[str]) -> dict[str, Any]:
    text = path.read_text(encoding="utf-8")
    missing = [heading for heading in required_headings if heading not in text]
    return {
        "path": path.relative_to(REPO).as_posix(),
        "size_bytes": path.stat().st_size,
        "sha256": sha256_file(path),
        "required_headings": required_headings,
        "missing_headings": missing,
        "status": "passed" if not missing and path.stat().st_size > 500 else "failed",
    }


