        "job_id": job_id,
        "phase_id": phase["phase_id"],
        "phase_name": phase["phase_name"],
        "status": "queued",
        "trigger": {
            "type": "phase_advancement",
            "source": source,
            "requested_by": "controller",
        },
        "authority": {
            "policy_version": "1.0",
            "autonomy_tier": "A1",
            "approval_required": False,
            "approval_type": None,
        },
        "limits": {
            "max_duration_seconds": 900,
            "max_retries": 1,
            "max_artifacts": 25,
            "max_total_bytes": 2_000_000,
        },
        "started_at": now,
        "updated_at": now,
        "last_heartbeat": now,
        "current_step": "queued",
        "completed_steps": [],
        "artifacts": [],
        "approval_id": None,
        "retry_count": 0,
        "n8n_execution_ids": [],
        "error": None,
    }
    save_job(job)
    return job


